To find the shortest path in an unweighted undirected graph, use a breadth-first search (BFS) algorithm, which explores all the neighbor nodes at the present depth prior to moving on to nodes at the next depth level.

```python
from collections import deque

def shortest_path_bfs(n, edges, src, dst):
    graph = [[] for _ in range(n)]
    for u, v in edges:
        graph[u].append(v)
        graph[v].append(u)
    queue = deque([(src, 0)])
    visited = {src}
    while queue:
        node, length = queue.popleft()
        if node == dst:
            return length
        for neighbor in graph[node]:
            if neighbor not in visited:
                queue.append((neighbor, length + 1))
                visited.add(neighbor)
    return -1
```
